-- Migration 004: tabelas extras (pesquisas, eventos, conversas, movimentacoes, notificacoes, atividades)
-- Execute apos a 003. CREATE IF NOT EXISTS + seed idempotente.


CREATE TABLE IF NOT EXISTS `pesquisas` (
  `id` VARCHAR(40) PRIMARY KEY,
  `titulo` VARCHAR(200),
  `data` VARCHAR(40),
  `amostra` INT DEFAULT 0,
  `intencao` JSON,
  `perguntas` JSON
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE IF NOT EXISTS `eventos` (
  `id` VARCHAR(40) PRIMARY KEY,
  `titulo` VARCHAR(200),
  `data` VARCHAR(40),
  `local` VARCHAR(200),
  `bairro` VARCHAR(120),
  `tipo` VARCHAR(60),
  `status` VARCHAR(40),
  `confirmados` INT DEFAULT 0
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE IF NOT EXISTS `conversas` (
  `id` VARCHAR(40) PRIMARY KEY,
  `eleitor_id` VARCHAR(40),
  `nome` VARCHAR(120),
  `bairro` VARCHAR(120),
  `tags` JSON,
  `nao_lidas` INT DEFAULT 0,
  `online` TINYINT(1) DEFAULT 0,
  `mensagens` JSON
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE IF NOT EXISTS `movimentacoes` (
  `id` VARCHAR(40) PRIMARY KEY,
  `descricao` VARCHAR(200),
  `categoria` VARCHAR(60),
  `tipo` VARCHAR(20),
  `valor` INT DEFAULT 0,
  `data` VARCHAR(40)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE IF NOT EXISTS `notificacoes` (
  `id` VARCHAR(40) PRIMARY KEY,
  `titulo` VARCHAR(200),
  `corpo` TEXT,
  `tempo` VARCHAR(40),
  `lida` TINYINT(1) DEFAULT 0,
  `tipo` VARCHAR(20)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE IF NOT EXISTS `atividades` (
  `id` VARCHAR(40) PRIMARY KEY,
  `usuario` VARCHAR(120),
  `acao` VARCHAR(120),
  `alvo` VARCHAR(120),
  `tempo` VARCHAR(40),
  `tipo` VARCHAR(40)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

